type WebAuthnEventHandlerBase<T extends Record<PropertyKey, unknown>> = {
  storeChallenge: (event: H3Event, challenge: string, attemptId: string) => void | Promise<void>
  getChallenge: (event: H3Event, attemptId: string) => string | Promise<string>
  onSuccess: (event: H3Event, data: T) => void | Promise<void>
  onError?: (event: H3Event, error: H3Error) => void | Promise<void>
} | {
  storeChallenge?: undefined
  getChallenge?: undefined
  onSuccess: (event: H3Event, data: T) => void | Promise<void>
  onError?: (event: H3Event, error: H3Error) => void | Promise<void>
}

switch (channel) {
  case 'nightly':
    return getNightlyVersion(packageNames)
  case 'v3':
    return { npmPackages: packageNames.map(p => `${p}@3`), nuxtVersion: '3.x' }
  case 'v3-nightly':
    return { npmPackages: packageNames.map(p => getNightlyDependency(p, '3.x')), nuxtVersion: '3.x' }
  case 'v4':
    return { npmPackages: packageNames.map(p => `${p}@4`), nuxtVersion: '4.x' }
  case 'v4-nightly':
    return { npmPackages: packageNames.map(p => getNightlyDependency(p, '4.x')), nuxtVersion: '4.x' }
  case 'stable':
  default:
    return { npmPackages: packageNames.map(p => `${p}@latest`), nuxtVersion: '4.x' }
}

